};

const computeNextGeneration = (cells: Cell[]): Cell[] => {
  const alive = new Set(cells.map(...));  // assignment(6) + invocation(2) + invocation(2) + loop(5) + binding(1)
  const neighborCounts = new Map<...>();  // assignment(6) + invocation(2) + binding(1)

  for (const [x, y] of cells) {          // loop(5) + binding(1) + binding(1)
    for (let dx = -1; dx <= 1; dx++) {   // loop(5) + binding(1) + constant(1) + constant(1) + assignment(6)
      for (let dy = -1; dy <= 1; dy++) { // loop(5) + binding(1) + constant(1) + constant(1) + assignment(6)
        if (dx === 0 && dy === 0) continue; // conditional(4) + constant(1) + constant(1)
        const key = `${x+dx},${y+dy}`;  // assignment(6) + binding(1) + binding(1) + binding(1) + binding(1)
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1); // invocation(2) + invocation(2) + conditional(4) + constant(1) + constant(1)
      }
    }
  }

  const next: Cell[] = [];               // assignment(6) + binding(1) + constant(1)
  for (const [key, count] of neighborCounts) { // loop(5) + binding(1) + binding(1)
    const [x, y] = key.split(",").map(Number) as Cell; // assignment(6) + binding(1) + binding(1) + invocation(2) + invocation(2)
    if (count === 3 || (count === 2 && alive.has(key))) { // conditional(4) + constant(1) + constant(1) + invocation(2)
      next.push([x, y]);                 // invocation(2) + binding(1) + binding(1)
    }
  }

  return next.sort(...);                 // invocation(2) + loop(5) + binding(1) + binding(1) + binding(1) + binding(1) + conditional(4) + binding(1) + binding(1)
